import sys
MOD = 998244353

def main():
    S = sys.stdin.readline().strip()
    n = len(S)
    dp = [[0] * (n + 1) for _ in range(n + 1)]
    dp[0][0] = 1

    for i in range(n):
        for j in range(n + 1):
            if dp[i][j]:
                # Try replacing '?' with '('
                if S[i] in ('?', '('):
                    dp[i + 1][j + 1] = (dp[i + 1][j + 1] + dp[i][j]) % MOD
                # Try replacing '?' with ')'
                if S[i] in ('?', ')'):
                    if j > 0:
                        dp[i + 1][j - 1] = (dp[i + 1][j - 1] + dp[i][j]) % MOD

    print(dp[n][0])

if __name__ == "__main__":
    main()
